import{_ as t,c as a,o,ae as r}from"./chunks/framework.CMFi8ROq.js";const u=JSON.parse('{"title":"状态更新过程","description":"","frontmatter":{},"headers":[],"relativePath":"note/framework/react/状态更新过程.md","filePath":"note/framework/react/状态更新过程.md","lastUpdated":null}'),p={name:"note/framework/react/状态更新过程.md"};function d(c,e,n,s,l,_){return o(),a("div",null,e[0]||(e[0]=[r('<h1 id="状态更新过程" tabindex="-1">状态更新过程 <a class="header-anchor" href="#状态更新过程" aria-label="Permalink to &quot;状态更新过程&quot;">​</a></h1><h2 id="状态更新的-三部曲" tabindex="-1">状态更新的“三部曲” <a class="header-anchor" href="#状态更新的-三部曲" aria-label="Permalink to &quot;状态更新的“三部曲”&quot;">​</a></h2><p>当我们调用 <code>setCount(prev =&gt; prev + 1)</code> 时，React 内部经历了以下过程：</p><p><strong>第一步：创建 Update 对象</strong></p><p>React 会创建一个 Update 对象，记录本次更新的动作（比如是一个具体的值，还是一个函数）。</p><p><strong>第二步：入队与调度</strong></p><p>这个 Update 会被推入该 Hook 自身的 queue 中。同时，React 会触发一个“调度”任务。它并不会立即重新渲染组件，而是通知调度器（Scheduler）：“这个组件有变化，请在空闲时安排一次演习。”</p><p><strong>第三步：Render 阶段的“状态合并”</strong></p><p>当 React 决定重新渲染该组件时：</p><ul><li><p>重新执行函数组件。</p></li><li><p>再次运行到 <code>useState</code> 时，React 会遍历 <code>queue</code> 里的所有 Update。</p></li><li><p>根据上一次的状态，依次执行这些 Update，最终计算出最新的 <code>memoizedState</code>。</p></li></ul>',10)]))}const m=t(p,[["render",d]]);export{u as __pageData,m as default};
